<?php
declare(strict_types=1);
if($path!=='/admin/notifications')return;
require_login();if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}
if($method==='POST'){verify_csrf();$email=trim((string)post('operational_alert_email'));if(!filter_var($email,FILTER_VALIDATE_EMAIL)){flash('error','Enter a valid notification email address.');redirect('/admin/notifications');}$level=in_array(post('operational_alert_level'),['warning','error'],true)?post('operational_alert_level'):'error';$values=['operational_alerts_enabled'=>post('operational_alerts_enabled')?'1':'0','operational_alert_email'=>$email,'operational_alert_level'=>$level,'operational_alert_cooldown_hours'=>(string)max(1,min(168,(int)post('operational_alert_cooldown_hours'))),'operational_webhook_failure_threshold'=>(string)max(1,min(100,(int)post('operational_webhook_failure_threshold')))];$save=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($values as $key=>$value)$save->execute([$key,$value]);if(post('action')==='test'){try{crm_send_email($email,'['.app_setting('app_name','OpenCRM').'] operational notification test',"Operational notifications are configured correctly.\n\nSystem health: ".rtrim((string)config('url'),'/').'/admin/health',true);flash('success','Test notification sent.');}catch(Throwable $e){flash('error','Test notification failed: '.$e->getMessage());}}else flash('success','Operational notification settings saved.');audit('update','operational_notification_settings',null,['enabled'=>$values['operational_alerts_enabled'],'level'=>$level,'recipient'=>$email]);redirect('/admin/notifications');}
$s=app_settings();$states=db()->query('SELECT * FROM operational_alert_states ORDER BY current_status DESC,updated_at DESC')->fetchAll();layout('Operational notifications',function()use($s,$states){?><h1>Operational notifications</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label><input type="checkbox" name="operational_alerts_enabled" value="1" style="width:auto" <?=$s['operational_alerts_enabled']==='1'?'checked':''?>> Email operational alerts</label><div class="form-grid"><label>Administrator recipient<input type="email" name="operational_alert_email" value="<?=e($s['operational_alert_email']?:$s['mail_from_address'])?>" required></label><label>Minimum severity<select name="operational_alert_level"><option value="error">Errors only</option><option value="warning" <?=$s['operational_alert_level']==='warning'?'selected':''?>>Warnings and errors</option></select></label><label>Repeat cooldown (hours)<input type="number" name="operational_alert_cooldown_hours" min="1" max="168" value="<?=e($s['operational_alert_cooldown_hours'])?>"></label><label>Webhook failures per hour before alert<input type="number" name="operational_webhook_failure_threshold" min="1" max="100" value="<?=e($s['operational_webhook_failure_threshold'])?>"></label></div><p class="muted">A new incident sends once, repeats only after the cooldown while unresolved, and sends a recovery notice when healthy again.</p><div class="actions"><button name="action" value="save">Save settings</button><button class="secondary" name="action" value="test">Save and send test</button></div></form><div class="card"><h2>Incident state</h2><table><thead><tr><th>Check</th><th>Status</th><th>Consecutive failures</th><th>Last checked</th><th>Last notification</th><th>Message</th></tr></thead><tbody><?php foreach($states as $row):?><tr><td><?=e($row['alert_key'])?></td><td><?=e($row['current_status'])?></td><td><?=$row['consecutive_failures']?></td><td><?=e($row['last_checked_at'])?></td><td><?=e($row['last_notified_at']?:'Never')?></td><td><?=e($row['last_message'])?></td></tr><?php endforeach?></tbody></table><?php if(!$states):?><p class="muted">No scheduled health check has recorded a state yet.</p><?php endif?></div><?php });exit;

